   `Ran(state) % n` is reduced mod n into the same range, so the contract is a
   pure memory-safety specification over an n-sized buffer.  Requiring n > 0
   keeps the `% n` reduction well defined (and the read in range); is_fresh on
   both pointers fixes the object sizes so the OOB-write mutant `i <= n` and the
   OOB-read mutant `Ran(state) * n` both escape the buffer and are caught.

   This is a depth-200 vacuity case: the loop body's first spec point (the OOB
   read inside the `if` branch) only becomes reachable at CBMC --depth ~290+, so
   both OOB mutants verify-fail (are killed) at depth >=400 but survive at the
   scored depth 200.  The remaining mutants are inherently unkillable by any
   sound spec: `i > n` / `i >= n` / `i == n` skip the loop and differ only in
   the (data-dependent, non-pinnable) final RNG state; `i != n` is equivalent to
   `i < n`; and the two `if`-condition mutants only change which random entries
   are copied, leaving every freqs value within the original value set, so no
   value postcondition distinguishes them.  Lowering the unwind, inlining Ran,
   and the r_ok lever were all tried and none brings the frontier under 200. */
static void RandomizeFreqs(RanState *state, size_t *freqs, int n)
__CPROVER_requires(n > 0)
__CPROVER_requires(__CPROVER_is_fresh(state, sizeof(*state)))
__CPROVER_requires(__CPROVER_is_fresh(freqs, (size_t)n * sizeof(size_t)))
__CPROVER_assigns(__CPROVER_object_whole(freqs))
__CPROVER_assigns(*state)
// clang-format on
{
    int i;
    for (i = 0; i < n; i++)
    {
        if ((Ran(state) >> 4) % 3 == 0)
            freqs[i] = freqs[Ran(state) % n];
    }
}

static void RandomizeStatFreqs(RanState *state, SymbolStats *stats)
{
    RandomizeFreqs(state, stats->litlens, ZOPFLI_NUM_LL);
    RandomizeFreqs(state, stats->dists, ZOPFLI_NUM_D);
    stats->litlens[256] = 1; /* End symbol. */
}

